def pathSum(nums):
    nodes = {n // 10: n % 10 for n in nums}
    self.res = 0
    def dfs(node, cur_sum):
        d, p = node // 10, node % 10
        cur_sum += nodes[node]
        left = (d + 1) * 10 + 2 * p - 1
        right = (d + 1) * 10 + 2 * p
        if left not in nodes and right not in nodes:
            self.res += cur_sum
            return
        if left in nodes: dfs(left, cur_sum)
        if right in nodes: dfs(right, cur_sum)
    if nums: dfs(nums[0] // 10, 0)
    return self.res

